```
config/routes.oas.json
{
"paths": {
"/hello": {
"x-zuplo-path": {
"pathMode": "open-api"
},
"get": {
"summary": "Hello World",
"x-my-custom-config": 10,
"x-zuplo-route": {
"corsPolicy": "none",
